#!/usr/bin/python

import sys

n, k = map(int, sys.stdin.readline().split())
a = map(int, sys.stdin.readline().split())

odd = []
even = []

for i in range(0, n):
	if i % 2 == 0:
		even.append(a[i])
	else:
		odd.append(a[i])

odd.sort()
even.sort()

if len(odd) >= k:
	odd = odd[len(odd) - k:]
else:
	even = even[len(even) - k:]

print min(max(odd), max(even))
